import Foundation
import UIKit

// MARK: - Analytics Module

class Analytics {

    static let shared = Analytics()

    private init() {
        // Optional: Add any setup here, e.g., registering for notifications
    }

    // MARK: - Configuration

    var isLoggingEnabled: Bool = true
    var currentUserID: String?
    var currentUserEmail: String?

    // MARK: - Core Logging Function

    private func log(_ message: String, level: String = "INFO", file: String = #file, function: String = #function, line: Int = #line) {
        guard isLoggingEnabled else { return }

        let fileName = (file as NSString).lastPathComponent
        let timestamp = DateFormatter.localizedString(from: Date(), dateStyle: .short, timeStyle: .medium)

        var logMessage = "[\(timestamp)] [\(level)] [\(fileName):\(line)] \(function) - \(message)"

        if let userID = currentUserID {
            logMessage += " (User ID: \(userID))"
        }
        if let email = currentUserEmail {
            logMessage += " (Email: \(email))"
        }

        NSLog("%@", logMessage) // Use NSLog for better integration with Console.app and crash reports
        print(logMessage) // Also print to Xcode console for immediate debugging
    }

    // MARK: - User Identification

    func identifyUser(id: String?, email: String?) {
        self.currentUserID = id
        self.currentUserEmail = email
        log("User identified. ID: \(id ?? "nil"), Email: \(email ?? "nil")", level: "DEBUG")
    }

    func clearUserIdentification() {
        let oldUserID = currentUserID
        let oldUserEmail = currentUserEmail
        self.currentUserID = nil
        self.currentUserEmail = nil
        log("User identification cleared. Previous ID: \(oldUserID ?? "nil"), Email: \(oldUserEmail ?? "nil")", level: "DEBUG")
    }

    // MARK: - Screen Tracking

    func trackScreenView(screenName: String, properties: [String: Any]? = nil) {
        var message = "Screen Viewed: \(screenName)"
        if let properties = properties, !properties.isEmpty {
            message += " Properties: \(properties)"
        }
        log(message)
    }

    // MARK: - User Interaction Tracking

    func trackEvent(name: String, properties: [String: Any]? = nil) {
        var message = "Event: \(name)"
        if let properties = properties, !properties.isEmpty {
            message += " Properties: \(properties)"
        }
        log(message)
    }

    func trackButtonTap(buttonName: String, screen: String? = nil) {
        var message = "Button Tapped: \(buttonName)"
        if let screen = screen {
            message += " on Screen: \(screen)"
        }
        log(message)
    }

    func trackGesture(gestureType: String, screen: String? = nil, element: String? = nil) {
        var message = "Gesture: \(gestureType)"
        if let screen = screen {
            message += " on Screen: \(screen)"
        }
        if let element = element {
            message += " on Element: \(element)"
        }
        log(message)
    }

    // MARK: - Authentication Flow Tracking

    func trackLoginAttempt(method: String, success: Bool, error: Error? = nil) {
        var message = "Login Attempt - Method: \(method), Success: \(success)"
        if let error = error {
            message += ", Error: \(error.localizedDescription)"
        }
        log(message, level: success ? "INFO" : "ERROR")
    }

    func trackLoginSuccess(userID: String, email: String?, token: String?) {
        identifyUser(id: userID, email: email)
        var message = "Login Success - User ID: \(userID)"
        if let email = email {
            message += ", Email: \(email)"
        }
        if let token = token {
            message += ", Token (first 10 chars): \(token.prefix(10))..."
        }
        log(message, level: "INFO")
    }

    func trackLogout(userID: String?, email: String?) {
        var message = "Logout - User ID: \(userID ?? "nil")"
        if let email = email {
            message += ", Email: \(email)"
        }
        clearUserIdentification()
        log(message, level: "INFO")
    }

    func trackRegistrationAttempt(method: String, success: Bool, error: Error? = nil) {
        var message = "Registration Attempt - Method: \(method), Success: \(success)"
        if let error = error {
            message += ", Error: \(error.localizedDescription)"
        }
        log(message, level: success ? "INFO" : "ERROR")
    }

    func trackRegistrationSuccess(userID: String, email: String?) {
        identifyUser(id: userID, email: email)
        var message = "Registration Success - User ID: \(userID)"
        if let email = email {
            message += ", Email: \(email)"
        }
        log(message, level: "INFO")
    }

    // MARK: - API Call Tracking

    func trackAPIRequest(endpoint: String, method: String, headers: [String: String]? = nil, payload: Data? = nil) {
        var message = "API Request - Endpoint: \(endpoint), Method: \(method)"
        if let headers = headers, !headers.isEmpty {
            message += ", Headers: \(headers)"
        }
        if let payload = payload, let payloadString = String(data: payload, encoding: .utf8) {
            message += ", Payload: \(payloadString)"
        }
        log(message, level: "DEBUG")
    }

    func trackAPIResponse(endpoint: String, method: String, statusCode: Int, responseData: Data? = nil, error: Error? = nil) {
        var message = "API Response - Endpoint: \(endpoint), Method: \(method), Status: \(statusCode)"
        if let responseData = responseData, let responseString = String(data: responseData, encoding: .utf8) {
            message += ", Response: \(responseString)"
        }
        if let error = error {
            message += ", Error: \(error.localizedDescription)"
        }
        let level = (statusCode >= 200 && statusCode < 300) ? "INFO" : "ERROR"
        log(message, level: level)
    }

    // MARK: - User Data Changes

    func trackUserDataChange(field: String, oldValue: Any?, newValue: Any?) {
        let message = "User Data Change - Field: \(field), Old Value: \(oldValue ?? "nil"), New Value: \(newValue ?? "nil")"
        log(message, level: "INFO")
    }

    // MARK: - Error and Exception Tracking

    func trackError(_ error: Error, description: String? = nil, userInfo: [String: Any]? = nil) {
        var message = "Error: \(error.localizedDescription)"
        if let description = description {
            message += ", Description: \(description)"
        }
        if let nsError = error as NSError? {
            message += ", Domain: \(nsError.domain), Code: \(nsError.code)"
            if !nsError.userInfo.isEmpty {
                message += ", UserInfo: \(nsError.userInfo)"
            }
        }
        if let userInfo = userInfo, !userInfo.isEmpty {
            message += ", Additional Info: \(userInfo)"
        }
        log(message, level: "ERROR")
    }

    func trackFatalError(_ error: Error, description: String? = nil, userInfo: [String: Any]? = nil) {
        var message = "FATAL ERROR: \(error.localizedDescription)"
        if let description = description {
            message += ", Description: \(description)"
        }
        if let nsError = error as NSError? {
            message += ", Domain: \(nsError.domain), Code: \(nsError.code)"
            if !nsError.userInfo.isEmpty {
                message += ", UserInfo: \(nsError.userInfo)"
            }
        }
        if let userInfo = userInfo, !userInfo.isEmpty {
            message += ", Additional Info: \(userInfo)"
        }
        log(message, level: "FATAL")
    }

    func trackWarning(message: String, userInfo: [String: Any]? = nil) {
        var logMessage = "Warning: \(message)"
        if let userInfo = userInfo, !userInfo.isEmpty {
            logMessage += ", UserInfo: \(userInfo)"
        }
        log(logMessage, level: "WARNING")
    }

    // MARK: - App Lifecycle Tracking

    func trackAppLifecycle(event: String) {
        log("App Lifecycle Event: \(event)", level: "DEBUG")
    }
}

